from flask import request
from app.utils.website.get_pagename_from_url import get_pagename_from_url
from app.services.Technology_Department.frontend_development.actions.getActiveTheme import getActiveTheme

def get_default_data(page_params=None):
    """
    Récupère les données par défaut pour une page ou pour l'admin.

    Args:
        page_params (dict, optional): Les paramètres de la page.

    Returns:
        dict: Les données par défaut enrichies pour la page ou l'admin.
    """
    # Récupération du thème actif
    active_theme = getActiveTheme()

    # Définir les valeurs par défaut si page_params est manquant
    if not page_params:
        page_params = {"page_name": "home", "params": {}}

    page_name = page_params.get("page_name", "home")

    # Données par défaut pour l'admin
    if page_name == "admin":
